import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i+1] = prefix[i] + a[i]

    def check(k):
        if k * (k + 1) // 2 > n:
            return False
        INF = float('inf')
        suffix_max_valid = [-INF] * (n + 2)
        for s in range(k, 0, -1):
            L = k + 1 - s
            cur_valid = [-INF] * (n + 2)
            for i in range(n - L, -1, -1):
                seg_sum = prefix[i + L] - prefix[i]
                if s == k or suffix_max_valid[i + L] > seg_sum:
                    cur_valid[i] = seg_sum
                cur_valid[i] = max(cur_valid[i], cur_valid[i + 1])
            suffix_max_valid = cur_valid
        return suffix_max_valid[0] > -INF

    lo, hi = 0, int((2*n)**0.5) + 2
    while lo < hi:
        mid = (lo + hi + 1) // 2
        if check(mid):
            lo = mid
        else:
            hi = mid - 1
    print(lo)

t = int(input())
for _ in range(t):
    solve()

